var promptRegistry = pgTable("prompt_registry", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  promptKey: varchar("prompt_key", { length: 100 }).notNull().unique(),
  // Unique identifier like 'email.generation'
  name: text("name").notNull(),
  description: text("description"),
  promptType: promptTypeEnum("prompt_type").notNull().default("system"),
  promptScope: promptScopeEnum("prompt_scope").notNull().default("agent_type"),
  agentType: text("agent_type"),
  // 'voice', 'email', 'compliance', etc.
  category: promptCategoryEnum("category"),
  content: text("content").notNull(),
  // The actual prompt content
  defaultContent: text("default_content").notNull(),
  // Original from codebase
  isActive: boolean("is_active").notNull().default(true),
  isLocked: boolean("is_locked").notNull().default(false),
  // Prevent editing
  priority: integer("priority").notNull().default(50),
  // For ordering (0-100)
  tags: jsonb("tags").$type().default([]),
  sourceFile: text("source_file"),
  // Where the prompt came from
  sourceLine: integer("source_line"),
  sourceExport: text("source_export"),
  // Export name from source file
  // Enhanced governance fields
  department: promptDepartmentEnum("department"),
  promptFunction: promptFunctionEnum("prompt_function"),
  purpose: promptPurposeEnum("purpose"),
  aiModel: text("ai_model"),
  // e.g., 'gpt-4o', 'gpt-4o-mini', 'deepseek', 'gemini-2.0-flash'
  status: promptStatusEnum("status").notNull().default("live"),
  ownerId: varchar("owner_id").references(() => users.id, { onDelete: "set null" }),
  ownerDepartment: text("owner_department"),
  // Invocation and dependency tracking
  invocationPoint: jsonb("invocation_point").$type(),
  inputDependencies: jsonb("input_dependencies").$type(),
  // data sources, context layers
  outputDestination: jsonb("output_destination").$type(),
  // which entities consume the result
  version: integer("version").notNull().default(1),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  createdBy: varchar("created_by").references(() => users.id, { onDelete: "set null" }),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
  updatedBy: varchar("updated_by").references(() => users.id, { onDelete: "set null" })
}, (table) => ({
  promptKeyIdx: uniqueIndex("prompt_registry_key_idx").on(table.promptKey),
  categoryIdx: index("prompt_registry_category_idx").on(table.category),
  agentTypeIdx: index("prompt_registry_agent_type_idx").on(table.agentType),
  activeIdx: index("prompt_registry_active_idx").on(table.isActive),
  departmentIdx: index("prompt_registry_department_idx").on(table.department),
  functionIdx: index("prompt_registry_function_idx").on(table.promptFunction),
  purposeIdx: index("prompt_registry_purpose_idx").on(table.purpose),
  statusIdx: index("prompt_registry_status_idx").on(table.status),
  ownerIdx: index("prompt_registry_owner_idx").on(table.ownerId),
  modelIdx: index("prompt_registry_model_idx").on(table.aiModel)
}));
var promptVersions = pgTable("prompt_versions", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  promptId: varchar("prompt_id").notNull().references(() => promptRegistry.id, { onDelete: "cascade" }),
  version: integer("version").notNull(),
  content: text("content").notNull(),
  previousContent: text("previous_content"),
  changeDescription: text("change_description"),
  changedBy: varchar("changed_by").references(() => users.id, { onDelete: "set null" }),
  changedAt: timestamp("changed_at").notNull().defaultNow(),
  addedLines: integer("added_lines").default(0),
  removedLines: integer("removed_lines").default(0),
  modifiedLines: integer("modified_lines").default(0)
}, (table) => ({
  promptIdIdx: index("prompt_versions_prompt_id_idx").on(table.promptId),
  versionIdx: index("prompt_versions_version_idx").on(table.promptId, table.version)
}));
var insertPromptRegistrySchema = createInsertSchema(promptRegistry);
